#include <iostream>

class ComplexNumber {
private:
    double real;
    double imaginary;

public:
    ComplexNumber(double r = 0.0, double i = 0.0) : real(r), imaginary(i) {}

    double getReal() const { return real; }
    double getImaginary() const { return imaginary; }

    // Correct operator+ for comparison
    ComplexNumber correct_operator_plus(const ComplexNumber& other) const {
        return ComplexNumber(real + other.real, imaginary + other.imaginary);
    }

    // The operator+ with the semantic error
    ComplexNumber operator+(const ComplexNumber& other) {
        real += other.real;
        imaginary += other.imaginary;
        return *this;
    }

    void print() const {
        std::cout << real;
        if (imaginary >= 0) {
            std::cout << " + " << imaginary << "i";
        } else {
            std::cout << " - " << -imaginary << "i";
        }
        std::cout << std::endl;
    }
};

int main() {
    ComplexNumber c1(2.5, 3.0);
    ComplexNumber c2(1.5, -2.0);
    ComplexNumber c3 = c1 + c2; // This will modify c1
    std::cout << c3.getReal() << " " << c3.getImaginary() << " " << c1.getReal() << " " << c1.getImaginary() << std::endl;

    ComplexNumber c4(0.0, 0.0);
    ComplexNumber c5(5.0, 7.0);
    ComplexNumber c6 = c4 + c5; // This will modify c4
    std::cout << c6.getReal() << " " << c6.getImaginary() << " " << c4.getReal() << " " << c4.getImaginary() << std::endl;

    ComplexNumber c7(-1.0, -1.0);
    ComplexNumber c8(1.0, 1.0);
    ComplexNumber c9 = c7 + c8; // This will modify c7
    std::cout << c9.getReal() << " " << c9.getImaginary() << " " << c7.getReal() << " " << c7.getImaginary() << std::endl;

    return 0;
}
